  6→namespace Microsoft.Falcon.LibOnePortal.Utility
  7→{
  8→    using System.Runtime.InteropServices;
  9→    using System.Security.Cryptography.X509Certificates;
 10→    using System.Text.Json;
 11→    using System.Text.Json.Serialization;
 12→    using Microsoft.AspNetCore.Builder;
 13→    using Microsoft.AspNetCore.Hosting;
 14→    using Microsoft.Extensions.DependencyInjection;
 15→    using Microsoft.Extensions.Hosting;
 16→    using Microsoft.Falcon.AppSettings.V2;
 17→    using Microsoft.Falcon.Loader;
 18→
 19→    /// <summary>
 20→    /// OnePortalServiceSPA for IHostApplicationBuilder, which is recommended to use in ASP.NET Core 8.0 and later for SPA.
 21→    /// </summary>
 22→    public abstract class OnePortalServiceSPA
 23→    {
 24→        private const string OnePortalConfigPath = "Config/1p.config.json";
 25→        private readonly JsonSerializerOptions jsonOpts = new JsonSerializerOptions() { UnmappedMemberHandling = JsonUnmappedMemberHandling.Disallow };
 26→
 27→        /// <summary>
 28→        /// Initializes a new instance of the <see cref="OnePortalServiceSPA"/> class.
 29→        /// </summary>
 30→        public OnePortalServiceSPA()
 31→        {
 32→            if (File.Exists(OnePortalConfigPath))
 33→            {
 34→                this.OneportalConfig = JsonSerializer.Deserialize<OnePortalConfig>(File.ReadAllText(OnePortalConfigPath), options: this.jsonOpts) ?? new OnePortalConfig();
 35→            }
 36→            else
 37→            {
 38→                this.OneportalConfig = new OnePortalConfig();
 39→            }
 40→        }
 41→
 42→        /// <summary>
 43→        /// Gets service name.
 44→        /// </summary>
 45→        public abstract string Name { get; }
 46→
 47→        /// <summary>
 48→        /// Gets one portal config.
 49→        /// </summary>
 50→        public virtual OnePortalConfig OneportalConfig { get; private set; }
 51→
 52→        /// <summary>
 53→        /// Run Oneportal service.
 54→        /// </summary>
 55→        /// <typeparam name="T">Service implementation.</typeparam>
 56→        /// <param name="args">cmd args from main.</param>
 57→        /// <returns>async task.</returns>
 58→        public static Task RunAsync<T>(string[] args)
 59→            where T : OnePortalServiceSPA
 60→        {
 61→            var hostBuilder = WebApplication.CreateBuilder(args);
 62→            var services = hostBuilder.Services;
 63→            var onePortalServiceSPA = Activator.CreateInstance<T>();
 64→            onePortalServiceSPA.ConfigureHostApplicationBuilder(hostBuilder);
 65→            onePortalServiceSPA.ConfigureServices(services);
 66→            var applicationBuilder = hostBuilder.Build();
 67→            onePortalServiceSPA.ConfigureWebApplication(applicationBuilder);
 68→            return applicationBuilder.RunAsync();
 69→        }
 70→
 71→        /// <summary>
 72→        /// The Configuration method for HostApplicationBuilder.
 73→        /// </summary>
 74→        /// <param name="webApplicationBuilder">The host application builder.</param>
 75→        public virtual void ConfigureHostApplicationBuilder(WebApplicationBuilder webApplicationBuilder)
 76→        {
 77→            // to do detect change to the certificatioon file and restart the service to load the new file
 78→            var certPath = Environment.GetEnvironmentVariable("HTTPS_CERTIFICATE_FILE_PATH");
 79→
 80→            webApplicationBuilder.WebHost.ConfigureKestrel(s =>
 81→            {
 82→                const int ONEPORTAL_HTTP_PORT = 5004;
 83→                const int ONEPORTAL_HTTPS_PORT = 5005;
 84→                s.ListenAnyIP(ONEPORTAL_HTTP_PORT, options =>
 85→                {
 86→                });
 87→
 88→                s.ListenAnyIP(ONEPORTAL_HTTPS_PORT, options =>
 89→                {
 90→                    if (!string.IsNullOrEmpty(certPath))
 91→                    {
 92→                        var certificate = this.GetPemCertificate(certPath);
 93→                        options.UseHttps(certificate);
 94→                    }
 95→                    else
 96→                    {
 97→                        options.UseHttps();
 98→                    }
 99→                });
100→            });
101→        }
102→
103→        /// <summary>
104→        /// The Configuration method for WebApplication.
105→        /// </summary>
106→        /// <param name="webApp">webApp.</param>
107→        public virtual void ConfigureWebApplication(WebApplication webApp)
108→        {
109→            webApp.UseOnePortalSPA(this.OneportalConfig);
110→            webApp.MapControllers();
111→            webApp.MapFallbackToFile("/index.html");
112→        }
113→
114→        /// <summary>
115→        /// The services configuration method.
116→        /// </summary>
117→        /// <param name="services">The services collection.</param>
118→        public virtual void ConfigureServices(IServiceCollection services)
119→        {
120→            services.AddOnePortalFalconServicesSPA(this.Name, this.OneportalConfig);
121→            this.InjectDependencies(services);
122→        }
123→
124→        /// <summary>
125→        /// SetupDependencyInjection.
126→        /// </summary>
127→        /// <param name="services">services.</param>
128→        public abstract void InjectDependencies(IServiceCollection services);
129→
130→        /// <summary>
131→        /// Get the certificate from .pem file.
132→        /// </summary>
133→        /// <param name="certPemFilePath">file path to the file.</param>
134→        /// <returns>certificate.</returns>
135→        private X509Certificate2 GetPemCertificate(string certPemFilePath)
136→        {
137→            if (string.IsNullOrWhiteSpace(certPemFilePath))
138→            {
139→                throw new ArgumentNullException();
140→            }
141→
142→            var ext = Path.GetExtension(certPemFilePath);
143→            if (ext != ".pem")
144→            {
145→                throw new ArgumentException($"Invalid extension {ext} found in certificate file path {certPemFilePath}, .pem extension must be used");
146→            }
147→
148→            var certificate = X509Certificate2.CreateFromPemFile(
149→            certPemFilePath);
150→            return RuntimeInformation.IsOSPlatform(OSPlatform.Windows) ? new X509Certificate2(certificate.Export(X509ContentType.Pkcs12)) : certificate;
151→        }
152→    }
153→}
