public abstract class OnePortalServiceSPA
{
    private const string OnePortalConfigPath = "Config/1p.config.json";

    // Constructor: Loads OnePortalConfig from JSON
    public OnePortalServiceSPA()
    {
        if (File.Exists(OnePortalConfigPath))
        {
            this.OneportalConfig = JsonSerializer.Deserialize<OnePortalConfig>(
                File.ReadAllText(OnePortalConfigPath), 
                options: this.jsonOpts) ?? new OnePortalConfig();
        }
        else
        {
            this.OneportalConfig = new OnePortalConfig();
        }
    }

    public abstract string Name { get; }
    public virtual OnePortalConfig OneportalConfig { get; private set; }

    // Main entry point for async application
    public static Task RunAsync<T>(string[] args) where T : OnePortalServiceSPA
    {
        var hostBuilder = WebApplication.CreateBuilder(args);
        var onePortalServiceSPA = Activator.CreateInstance<T>();
        onePortalServiceSPA.ConfigureHostApplicationBuilder(hostBuilder);  // Configure ports/HTTPS
        onePortalServiceSPA.ConfigureServices(hostBuilder.Services);        // DI setup
        var applicationBuilder = hostBuilder.Build();
        onePortalServiceSPA.ConfigureWebApplication(applicationBuilder);    // Middleware pipeline
        return applicationBuilder.RunAsync();
    }

    // Host Configuration (lines 75-101)
    public virtual void ConfigureHostApplicationBuilder(WebApplicationBuilder webApplicationBuilder)
    {
        // Reads HTTPS_CERTIFICATE_FILE_PATH environment variable
        // Configures Kestrel:
        //   - HTTP: port 5004 (ONEPORTAL_HTTP_PORT)
        //   - HTTPS: port 5005 (ONEPORTAL_HTTPS_PORT)
        // Uses PEM certificate if available
    }

    // Web Application Configuration (lines 107-112)
    public virtual void ConfigureWebApplication(WebApplication webApp)
    {
        webApp.UseOnePortalSPA(this.OneportalConfig);  // Uses SPA extension
        webApp.MapControllers();
        webApp.MapFallbackToFile("/index.html");       // SPA fallback
    }

    // Service Registration (lines 118-122)
    public virtual void ConfigureServices(IServiceCollection services)
    {
        services.AddOnePortalFalconServicesSPA(this.Name, this.OneportalConfig);
        this.InjectDependencies(services);  // Abstract - implemented by subclasses
    }

    // Certificate Loading (lines 135-151)
