 16→    /// <summary>
 17→    /// OnePortalService.
 18→    /// </summary>
 19→    public abstract class OnePortalService
 20→    {
 21→        private const string OnePortalConfigPath = "Config/1p.config.json";
 22→        private readonly JsonSerializerOptions jsonOpts = new JsonSerializerOptions() { UnmappedMemberHandling = JsonUnmappedMemberHandling.Disallow };
 23→
 24→        /// <summary>
 25→        /// Initializes a new instance of the <see cref="OnePortalService"/> class.
 26→        /// </summary>
 27→        public OnePortalService()
 28→        {
 29→            if (File.Exists(OnePortalConfigPath))
 30→            {
 31→                this.OneportalConfig = JsonSerializer.Deserialize<OnePortalConfig>(File.ReadAllText(OnePortalConfigPath), options: this.jsonOpts) ?? new OnePortalConfig();
 32→            }
 33→            else
 34→            {
 35→                this.OneportalConfig = new OnePortalConfig();
 36→            }
 37→
 38→            this.OneportalConfig.OverrideConfigFromEnvVars();
 39→        }
 40→
 41→        /// <summary>
 42→        /// Gets service name.
 43→        /// </summary>
 44→        public abstract string Name { get; }
 45→
 46→        /// <summary>
 47→        /// Gets one portal config.
 48→        /// </summary>
 49→        public virtual OnePortalConfig OneportalConfig { get; private set; }
 50→
 51→        /// <summary>
 52→        /// Run Oneportal service.
 53→        /// </summary>
 54→        /// <typeparam name="T">Service implementation.</typeparam>
 55→        /// <param name="args">cmd args from main.</param>
 56→        /// <returns>async task.</returns>
 57→        public static Task RunAsync<T>(string[] args)
 58→            where T : OnePortalService
 59→        {
 60→            var hostBuilder = new HostBuilder();
 61→            hostBuilder.ConfigureFalcon<T>(args);
 62→            var onePortal = Activator.CreateInstance<T>();
 63→            onePortal.ConfigBuilder(hostBuilder);
 64→            var application = hostBuilder.Build();
 65→            return application.RunAsync();
 66→        }
 67→
 68→        /// <summary>
 69→        /// The services configuration method.
 70→        /// </summary>
 71→        /// <param name="services">The services collection.</param>
 72→        public void ConfigureServices(IServiceCollection services)
 73→        {
 74→            this.InjectDependencies(services);
 75→            services.AddOnePortalFalconServices(this.Name, this.OneportalConfig);
 76→        }
 77→
 78→        /// <summary>
 79→        /// The Configuration method.
 80→        /// </summary>
 81→        /// <param name="app">The application.</param>
 82→        public virtual void Configure(IApplicationBuilder app)
 83→        {
 84→            app.UseOnePortal(this.OneportalConfig);
 85→        }
