        {
            services.AddHttpClient();
            services.AddSingleton<IEnvironmentSetting, EnvironmentSetting>();
            services.AddSingleton<ISecretStore, GalaxyVaultSecretStore>();
            services.AddSingleton<IMicrosoftGraphApiClient, MicrosoftGraphApiClient>();

            services.AddSingleton<IArmClientWrapper, ArmClientAPIProxyWrapper>();
            services.AddSingleton<IArmRestApiWrapper, ArmRestClientAPIProxyWrapper>();

            services.AddSingleton<DBConnectionProperties>();
            services.AddScoped<IUnitOfCodeX, UnitOfCodeX>();
            services.AddSingleton<IAOAIClient>(sp => new AOAIClient(sp.GetService<ICredentialFactory>().CreateTokenCredential(AADTenant.PME)));
            services.AddSingleton<IOCIRestApiClient>(sp => new OCIRestApiClient(new BasicTokenCredAuthProvider(sp.GetService<ICredentialFactory>().CreateTokenCredential(AADTenant.PME))));
            services.AddSingleton<IPaiApiClient>(sp => new PaiApiClient(
                sp.GetService<System.Net.Http.IHttpClientFactory>(),
                sp.GetService<ICredentialFactory>().CreateTokenCredential(),
                sp.GetService<ILogger<PaiApiClient>>()));
            services.AddSingleton<IEnvironmentProperties, EnvironmentProperties>();
            services.AddSingleton<IPapyrusClient, PapyrusClient>();
            services.AddScoped<EndpointUpdater>();
            services.AddScoped<ISKUService, SKUService>();
            services.AddScoped<MssAndMpcpUpdater>();
            services.AddScoped<ICodeXService, CodeXService>();

            services.AddSingleton<IPerfHubStressTestService, PerfHubStressTestService>();
            services.AddSingleton<AdoCredentialFactory>();
            services.AddSingleton<IGitClient>(sp => new GitClient(new TokenProviderDelegatingHandler(new AzureCredentialTokenProvider(new[] { ISExpAuthToolkit.Constants.AzureADDevOpsScope }, sp.GetService<AdoCredentialFactory>().GetPrimaryAdoCredential()))));

            services.AddSingleton<PapyrusEnvironmentProperties>(sp => EnvUtil.ResolvePapyrusEnvProperties(sp.GetService<IEnvironmentProperties>()));
            services.AddSingleton<IPullRequestClient>(sp =>
            {
                var papyrusEnvProps = sp.GetService<PapyrusEnvironmentProperties>();
                var adoCredFactory = sp.GetService<AdoCredentialFactory>();
                return new PullRequestClient(
                    papyrusEnvProps.AdoOrg,
