//---------------------------------------------------------------------------------------------------------------------
// <copyright file="OnePortalApplicationBuilderExtension.cs" company="Microsoft">
// Copyright (c) Microsoft. All rights reserved.
// </copyright>
//---------------------------------------------------------------------------------------------------------------------

namespace Microsoft.Falcon.LibOnePortal.Utility
{
    using System;
    using System.Net;
    using global::LibOnePortal.Middleware;
    using global::LibOnePortal.Utility;
    using Microsoft.AspNetCore.Authentication.OpenIdConnect;
    using Microsoft.AspNetCore.Authorization;
    using Microsoft.AspNetCore.Builder;
    using Microsoft.AspNetCore.Diagnostics;
    using Microsoft.AspNetCore.Hosting;
    using Microsoft.AspNetCore.Http;
    using Microsoft.AspNetCore.SpaServices.ReactDevelopmentServer;
    using Microsoft.Extensions.DependencyInjection;
    using Microsoft.Extensions.Hosting;
    using Microsoft.Falcon.FalconWebCore;

    /// <summary>
    /// Provides extension methods for configuring the OnePortal application.
    /// </summary>
    public static class OnePortalApplicationBuilderExtension
    {
        /// <summary>
        /// Configures the application to use OnePortal services and middleware.
        /// It follow the latest template for ASP.NET Core 8.0 and later. Need to use with AddOnePortalFalconServicesSPA.
        /// </summary>
        /// <param name="app">The application builder.</param>
        /// <param name="oneportalConfig">oneportalConfig.</param>
        /// <exception cref="ArgumentNullException">Thrown when <paramref name="app"/> is null.</exception>
        public static void UseOnePortalSPA(this IApplicationBuilder app, OnePortalConfig oneportalConfig)
        {
            if (app == null)
            {
                throw new ArgumentNullException(nameof(app));
            }

            var envProps = app.ApplicationServices.GetService<IEnvironmentProperties>();

            app.UseDefaultFiles();
            app.UseStaticFiles();

            app.UseMiddleware<OnePortalMiddleware>();
            app.UseWebSockets();

            app.UseRouting();

            if (envProps!.Environment != EnvironmentEnum.ProductionEnvironment)
            {
                app.UseDeveloperExceptionPage();
            }

            var cookiePolicyOptions = new CookiePolicyOptions
            {
                Secure = CookieSecurePolicy.Always,
                CheckConsentNeeded = context => true,
            };
            app.UseCookiePolicy(cookiePolicyOptions);

            app.UseAuthentication();
            app.UseAuthorization();

            // Configure the HTTP request pipeline.
            app.UseSwagger();
            app.UseSwaggerUI(c =>
            {
                c.OAuthUsePkce();
                c.OAuthClientId(oneportalConfig.AADAuthAppId);
            });

            app.UseExceptionHandler(
                options =>
                {
                    options.Run(
                        async context =>
                        {
                            context.Response.StatusCode = (int)HttpStatusCode.InternalServerError;
                            var exContext = context.Features.Get<IExceptionHandlerFeature>();
                            if (exContext != null)
                            {
                                if (exContext.Error is UserException)
                                {
                                    context.Response.StatusCode = UserException.UserErrorStatusCode;
                                    await context.Response.WriteAsJsonAsync((exContext.Error as UserException)!.GetUserError()).ConfigureAwait(false);
                                }
                                else
                                {
                                    throw exContext.Error;
                                }
                            }
                        });
                });

            app.UseEndpoints(endpoints =>
            {
                var pipeline = endpoints.CreateApplicationBuilder().Build();

                endpoints.Map("/swagger", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
                endpoints.Map("/swagger/index.html", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
                endpoints.Map("/swagger/v1/swagger.json", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
                endpoints.Map("/swagger/{documentName}/swagger.json", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
                endpoints.MapControllers();
            });

            app.UseHttpsRedirection();
        }

        /// <summary>
        /// Configures the application to use OnePortal services and middleware.
        /// </summary>
        /// <param name="app">The application builder.</param>
        /// <param name="oneportalConfig">oneportalConfig.</param>
        /// <exception cref="ArgumentNullException">Thrown when <paramref name="app"/> is null.</exception>
        public static void UseOnePortal(this IApplicationBuilder app, OnePortalConfig oneportalConfig)
        {
            if (app == null)
            {
                throw new ArgumentNullException(nameof(app));
            }

            app.UseMiddleware<OnePortalMiddleware>();
            app.UseWebSockets();

            var envProps = app.ApplicationServices.GetService<IEnvironmentProperties>();

            app.UseStaticFiles();
            if (!oneportalConfig.EnableProxy)
            {
                app.UseSpaStaticFiles();
            }

            app.UseRouting();

            if (envProps!.Environment != EnvironmentEnum.ProductionEnvironment)
            {
                app.UseDeveloperExceptionPage();
            }

            var cookiePolicyOptions = new CookiePolicyOptions
            {
                Secure = CookieSecurePolicy.Always,
                CheckConsentNeeded = context => true,
            };
            app.UseCookiePolicy(cookiePolicyOptions);

            app.UseAuthentication();
            app.UseAuthorization();
            if (!oneportalConfig.EnableProxy)
            {
                app.UseSwagger();
                app.UseSwaggerUI(c =>
                {
                    c.OAuthUsePkce();
                    c.OAuthClientId(oneportalConfig.AADAuthAppId);
                });
            }

            app.UseExceptionHandler(
                options =>
                {
                    options.Run(
                        async context =>
                        {
                            context.Response.StatusCode = (int)HttpStatusCode.InternalServerError;
                            var exContext = context.Features.Get<IExceptionHandlerFeature>();
                            if (exContext != null)
                            {
                                if (exContext.Error is UserException)
                                {
                                    context.Response.StatusCode = UserException.UserErrorStatusCode;
                                    await context.Response.WriteAsJsonAsync((exContext.Error as UserException)!.GetUserError()).ConfigureAwait(false);
                                }
                                else
                                {
                                    throw exContext.Error;
                                }
                            }
                        });
                });

            app.UseEndpoints(endpoints =>
            {
                if (!oneportalConfig.EnableProxy)
                {
                    var pipeline = endpoints.CreateApplicationBuilder().Build();
                    endpoints.Map("/swagger", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
                    endpoints.Map("/swagger/index.html", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
                    endpoints.Map("/swagger/v1/swagger.json", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
                    endpoints.Map("/swagger/{documentName}/swagger.json", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
                    endpoints.MapRazorPages();
                }

                endpoints.MapControllers();

                if (oneportalConfig.EnableProxy)
                {
                    var handler = new ProxyHandler(oneportalConfig.ProxyDestUrl, oneportalConfig.SkipProxySslValidation);
                    endpoints.Map("{*anyURI}", handler.Handle).RequireAuthorization();
                }
            });

            if (!oneportalConfig.EnableProxy)
            {
                app.UseSpa(spa =>
                {
                    spa.Options.SourcePath = "ClientApp";
                    if (envProps!.Environment == EnvironmentEnum.DevMachine)
                    {
                        spa.UseReactDevelopmentServer(npmScript: "start");
                    }
                });
            }

            app.UseWarmup();
        }
    }
}

