 1→/* eslint-disable @typescript-eslint/no-var-requires */
 2→const { createProxyMiddleware } = require('http-proxy-middleware');
 3→const { env } = require('process');
 4→
 5→/* eslint-disable-next-line no-nested-ternary */
 6→const target = env.ASPNETCORE_HTTPS_PORT ? `https://localhost:${env.ASPNETCORE_HTTPS_PORT}`
 7→  : env.ASPNETCORE_URLS ? env.ASPNETCORE_URLS.split(';')[0] : 'http://localhost:9320';
