 1→// This script configures the .env.development.local file with additional environment variables to configure HTTPS using the ASP.NET Core
 2→// development certificate in the webpack development proxy.
 3→
 4→const fs = require('fs');
 5→const path = require('path');
 6→
 7→const baseFolder =
 8→  process.env.APPDATA !== undefined && process.env.APPDATA !== ''
 9→    ? `${process.env.APPDATA}/ASP.NET/https`
10→    : `${process.env.HOME}/.aspnet/https`;
11→
12→const certificateArg = process.argv.map(arg => arg.match(/--name=(?<value>.+)/i)).filter(Boolean)[0];
13→const certificateName = certificateArg ? certificateArg.groups.value : process.env.npm_package_name;
14→
15→if (!certificateName) {
16→  console.error('Invalid certificate name. Run this script in the context of an npm/yarn script or pass --name=<<app>> explicitly.')
17→  process.exit(-1);
18→}
19→
20→const certFilePath = path.join(baseFolder, `${certificateName}.pem`);
21→const keyFilePath = path.join(baseFolder, `${certificateName}.key`);
22→
23→if (!fs.existsSync('.env.development.local')) {
24→  fs.writeFileSync(
25→    '.env.development.local',
26→`SSL_CRT_FILE=${certFilePath}
27→SSL_KEY_FILE=${keyFilePath}`
28→  );
29→} else {
30→  let lines = fs.readFileSync('.env.development.local')
31→    .toString()
32→    .split('\n');
33→
34→  let hasCert, hasCertKey = false;
35→  for (const line of lines) {
36→    if (/SSL_CRT_FILE=.*/i.test(line)) {
37→      hasCert = true;
38→    }
39→    if (/SSL_KEY_FILE=.*/i.test(line)) {
40→      hasCertKey = true;
41→    }
42→  }
43→  if (!hasCert) {
44→    fs.appendFileSync(
45→      '.env.development.local',
46→      `\nSSL_CRT_FILE=${certFilePath}`
47→    );
48→  }
49→  if (!hasCertKey) {
50→    fs.appendFileSync(
51→      '.env.development.local',
52→      `\nSSL_KEY_FILE=${keyFilePath}`
53→    );
54→  }
55→}
